import '../lib/export_name.dart';
import '../lib/report_bundle.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  check(portableSegment('CON') == '_CON', 'device names must be made portable');
  check(
    portableSegment('daily...  ') == 'daily',
    'trailing periods and spaces must be removed',
  );

  final bundle = ReportBundle();
  check(
    bundle.allocateEntry('Ops', 'Summary') == 'Ops/Summary.txt',
    'allocates the first case variant',
  );
  check(
    bundle.allocateEntry('ops', 'summary') == 'ops/summary (2).txt',
    'case-only variants share a collision domain',
  );

  print('feedback tests passed');
}
